1	// Pure functions for unified-diff parsing and line-in-diff validation.
2	// Uses parse-diff for parsing; exports only clean functional interfaces.
3	
4	import parseDiff from "parse-diff";
5	import type { Finding, Side } from "./schema.js";
6	
7	// A set of "path:line" keys present in the diff hunks (additions/changes).
8	// Used to validate findings before posting inline comments.
9	export type DiffLineIndex = ReadonlySet<string>;
10	
11	const key = (path: string, line: number): string => `${path}:${String(line)}`;
12	
13	/** Index a set of changes under a given file path. */
14	const indexChanges = (
15	  keys: Set<string>,
16	  fpath: string,
17	  changes: ReadonlyArray<{
18	    readonly type: "normal" | "add" | "del";
19	    readonly ln1?: number;
20	    readonly ln2?: number;
21	    readonly ln?: number;
22	  }>,
23	): void => {
24	  for (const change of changes) {
25	    if (change.type === "normal") {
26	      if (change.ln1 !== undefined) keys.add(key(fpath, change.ln1));
27	      if (change.ln2 !== undefined) keys.add(key(fpath, change.ln2));
28	    } else if (change.ln !== undefined) {
29	      keys.add(key(fpath, change.ln));
30	    }
31	  }
32	};
33	
34	/** Parse a unified diff string into a set of "path:line" keys for every line in the diff.
35	 *  For renamed files, both old and new paths are indexed so findings on either path match. */
36	export const indexDiff = (diff: string): DiffLineIndex => {
37	  const files = parseDiff(diff);
38	  if (!Array.isArray(files)) return new Set();
39	
40	  const keys = new Set<string>();
41	  for (const file of files) {
42	    // Deleted: file.to is /dev/null, use file.from
43	    // New: file.from is undefined, use file.to
44	    // Modified: both set and equal
45	    // Renamed: both set and differ → index both paths
46	    const primary = file.from ?? file.to;
47	    if (!primary) continue;
48	
49	    indexChanges(
50	      keys,
51	      primary,
52	      file.chunks.flatMap((c) => c.changes),
53	    );
54	
55	    // Also index under file.to for renames (when both paths exist and differ)
56	    if (file.to && file.to !== "/dev/null" && file.to !== primary) {
57	      indexChanges(
58	        keys,
59	        file.to,
60	        file.chunks.flatMap((c) => c.changes),
61	      );
62	    }
63	  }
64	  return keys;
65	};
66	
67	/** Check whether a finding's anchor line appears in the diff. */
68	export const isInDiff = (index: DiffLineIndex, path: string, line: number): boolean =>
69	  index.has(key(path, line));
70	
71	/** True for a diff with no content or no hunks — nothing to review or anchor inline comments to. */
72	export const isEmptyDiff = (diff: string): boolean => {
73	  if (diff.trim().length === 0) return true;
74	  const files = parseDiff(diff);
75	  return !Array.isArray(files) || files.length === 0 || files.every((f) => f.chunks.length === 0);
76	};
77	
78	/** Default side for inline comments: RIGHT for additions, LEFT for deletions. */
79	export const defaultSide = (side: string | undefined): Side => (side === "LEFT" ? "LEFT" : "RIGHT");
80	
81	/** Partition findings into in-diff and out-of-diff (strays). Strays get demoted to the summary. */
82	export const partitionFindings = (
83	  findings: readonly Finding[],
84	  index: DiffLineIndex,
85	): {
86	  readonly inDiff: readonly Finding[];
87	  readonly strays: readonly Finding[];
88	} => {
89	  const inDiff: Finding[] = [];
90	  const strays: Finding[] = [];
91	  for (const f of findings) {
92	    if (isInDiff(index, f.path, f.start_line) && isInDiff(index, f.path, f.end_line)) {
93	      inDiff.push(f);
94	    } else {
95	      strays.push(f);
96	    }
97	  }
98	  return { inDiff, strays };
99	};
