1	// Conservative markdown formatting pass applied just before a comment/review body is posted, plus
2	// small pure formatting helpers for the IO boundary (e.g. the sticky's posted-at timestamp).
3	// Pure string transform: never reflows content, never touches fenced code blocks (a `suggestion`
4	// block's blank lines and trailing whitespace are significant and must survive verbatim).
5	
6	interface ScanState {
7	  readonly lines: readonly string[];
8	  readonly inFence: boolean;
9	  readonly blankRun: number;
10	}
11	
12	const FENCE_RE = /^\s*```/;
13	
14	const scanLine = (state: ScanState, line: string): ScanState => {
15	  if (FENCE_RE.test(line)) {
16	    return { lines: [...state.lines, line], inFence: !state.inFence, blankRun: 0 };
17	  }
18	  if (state.inFence) {
19	    return { lines: [...state.lines, line], inFence: true, blankRun: 0 };
20	  }
21	  const trimmed = line.replace(/[ \t]+$/, "");
22	  if (trimmed !== "") {
23	    return { lines: [...state.lines, trimmed], inFence: false, blankRun: 0 };
24	  }
25	  const blankRun = state.blankRun + 1;
26	  return blankRun === 1
27	    ? { lines: [...state.lines, ""], inFence: false, blankRun }
28	    : { ...state, blankRun };
29	};
30	
31	/** Trim trailing whitespace and collapse runs of 2+ blank lines to one — never to zero — leaving
32	 *  exactly one trailing newline. Fenced (```) content passes through untouched. */
33	export const formatMarkdown = (md: string): string => {
34	  const { lines } = md
35	    .split("\n")
36	    .reduce<ScanState>(scanLine, { lines: [], inFence: false, blankRun: 0 });
37	  return `${lines.join("\n").replace(/\n+$/, "")}\n`;
38	};
39	
40	const pad2 = (n: number): string => String(n).padStart(2, "0");
41	
42	/** Format a Date as UTC `YYYY-MM-DD HH:MM UTC`, for the sticky's "**Reviewed** `<sha>` at
43	 *  <postedAt>" meta segment (issue #28). Computed at the IO boundary (index.ts's post/render
44	 *  commands) — `render()` itself stays pure/clockless and just receives the formatted string. */
45	export const formatUtc = (d: Date): string =>
46	  `${String(d.getUTCFullYear())}-${pad2(d.getUTCMonth() + 1)}-${pad2(d.getUTCDate())} ${pad2(d.getUTCHours())}:${pad2(d.getUTCMinutes())} UTC`;
